// Webhook-Daten lesen (snake_case JSON body)
const body = $json.body || $json;
const activityId = (body.activity_id || '').trim();
let leadId = (body.lead_id || '').trim();
let userId = (body.user_id || '').trim();
const formDatum = (body.datum || '').trim();
let formErgebnis = (body.ergebnis || '').trim();

const CLOSE_AUTH = 'Basic YXBpXzJKd0JqaHMwYmZCUmJ5d3dHeXA0blUuMWlWV0NZVUUyRzE3NWh6NjJmNEJMRzo=';
const EG_TYPE_ID = 'actitype_0Pow7dFbqAOrFjLsCT068D';
const ERGEBNIS_FIELD = 'custom.cf_Bp0LGE1a2Am7BlHszQNtV7KuTpVYDthbiKOetsFkcUQ';

let dateCreated = formDatum ? new Date(formDatum).toISOString() : new Date().toISOString();
let customFields = {};

// EG-Ergebnis setzen
if (formErgebnis) {
  customFields[ERGEBNIS_FIELD] = formErgebnis;
}

// Fall 1: Activity ID gegeben - Details aus Close holen
if (activityId) {
  const activity = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://api.close.com/api/v1/activity/custom/' + activityId + '/',
    headers: { 'Authorization': CLOSE_AUTH, 'Accept': 'application/json' }
  });
  leadId = leadId || activity.lead_id;
  userId = userId || activity.user_id || activity.created_by;
  if (!formDatum) dateCreated = activity.date_created || dateCreated;
  if (!formErgebnis && activity.custom) customFields = activity.custom;
}

// Fall 2: Nur Lead ID - letzte EG Activity suchen (fuer User ID + Datum)
if (!activityId && leadId && !userId) {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://api.close.com/api/v1/activity/custom/?lead_id=' + leadId + '&_limit=50&_order_by=-date_created',
      headers: { 'Authorization': CLOSE_AUTH, 'Accept': 'application/json' }
    });
    const parsed = typeof resp === 'string' ? JSON.parse(resp) : resp;
    const activities = (parsed.data || []).filter(a => a.custom_activity_type_id === EG_TYPE_ID);
    if (activities.length > 0) {
      const latest = activities[0];
      userId = latest.user_id || latest.created_by;
      if (!formDatum) dateCreated = latest.date_created || dateCreated;
      if (!formErgebnis && latest.custom) customFields = latest.custom;
    }
  } catch (e) { /* Weiter mit manuellen Daten */ }
}

if (!leadId) {
  throw new Error('Bitte mindestens lead_id oder activity_id im JSON body senden');
}

return [{ json: { leadId, userId, dateCreated, customFields, testMode: true } }];

const input = $json;
const testMode = input.testMode || false;
const ergebnis = (input.customFields || {})['custom.cf_Bp0LGE1a2Am7BlHszQNtV7KuTpVYDthbiKOetsFkcUQ'] || '';

const OPP_STATUS_MAP = {
  '1 - Kunde': 'stat_whEM29RxVUWk9pucJMWhPtBrjjadPn4DzUsYxV06bCs',
  '2 - Folgetermin': null,
  '3 - Follow-up': 'stat_2NjdTtgLsl931S2nrmOLTK7IWW7KV0JVsiTwS7zexT4',
  '4 - Verloren': 'stat_2NjdTtgLsl931S2nrmOLTK7IWW7KV0JVsiTwS7zexT4',
  '5 - Unqualifiziert': 'stat_0o8JNmzSa6GiQH5yEZ424xT9B08NGTia4U3VxxzssMB'
};

const DEFAULT_STATUS = 'stat_bMeIa40jGWwjbA5bOJpdIGgBk7QFWa1nlhsA9hVJg1J';
const targetOppStatus = OPP_STATUS_MAP.hasOwnProperty(ergebnis) ? OPP_STATUS_MAP[ergebnis] : DEFAULT_STATUS;

const now = new Date();
const closeDate = new Date(now.getTime() + 12 * 24 * 60 * 60 * 1000);
const closeDateStr = closeDate.toISOString().split('T')[0];

const date = new Date(input.dateCreated || now.toISOString());
const dayStart = new Date(date.getFullYear(), date.getMonth(), date.getDate()).toISOString();
const dayEnd = new Date(date.getFullYear(), date.getMonth(), date.getDate() + 1).toISOString();

return [{
  json: {
    ...input,
    testMode,
    ergebnis,
    targetOppStatus,
    closeDateStr,
    dayStart,
    dayEnd
  }
}];

const input = $json;
const CLOSE_AUTH = 'Basic YXBpXzJKd0JqaHMwYmZCUmJ5d3dHeXA0blUuMWlWV0NZVUUyRzE3NWh6NjJmNEJMRzo=';
const DEFAULT_STATUS = 'stat_bMeIa40jGWwjbA5bOJpdIGgBk7QFWa1nlhsA9hVJg1J';

const oppResp = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://api.close.com/api/v1/opportunity/?lead_id=' + input.leadId + '&status_type=active&_limit=1&_order_by=-date_created',
  headers: { 'Authorization': CLOSE_AUTH, 'Accept': 'application/json' }
});

const opportunities = oppResp.data || [];
let oppResult;

if (opportunities.length > 0) {
  const opp = opportunities[0];
  const updateBody = { close_date: input.closeDateStr };
  if (input.targetOppStatus) {
    updateBody.status_id = input.targetOppStatus;
  }
  oppResult = await this.helpers.httpRequest({
    method: 'PUT',
    url: 'https://api.close.com/api/v1/opportunity/' + opp.id,
    headers: { 'Authorization': CLOSE_AUTH, 'Content-Type': 'application/json' },
    body: JSON.stringify(updateBody)
  });
} else {
  const statusId = input.targetOppStatus || DEFAULT_STATUS;
  oppResult = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.close.com/api/v1/opportunity/',
    headers: { 'Authorization': CLOSE_AUTH, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      lead_id: input.leadId,
      status_id: statusId,
      value: 300000,
      value_period: 'one_time',
      value_currency: 'EUR',
      confidence: 33,
      date_created: input.dateCreated,
      close_date: input.closeDateStr,
      note: 'Automatisch erstellt durch EG stattgefunden Activity',
      user_id: input.userId
    })
  });
}

return [{ json: { ...input, oppResult } }];

const loopStart = $('Init Loop Counter').first().json.loopStartTime;
const elapsedMs = Date.now() - loopStart;
const maxWait = 20 * 60 * 1000; // 20 Minuten (ca. 10 Retries a 2 Min)

const response = $('GET Calls').first().json;
const callsData = response.data || [];
const calls = callsData.filter(c => c.recording_url);

if (calls.length === 0 && elapsedMs < maxWait) {
  return [{ json: { hasRecordings: false, maxReached: false } }];
}

if (calls.length === 0) {
  return [{ json: { hasRecordings: false, maxReached: true, calls: [] } }];
}

return [{ json: { hasRecordings: true, maxReached: false, calls } }];

// Originale Transcript-Daten aus Transcribe Calls holen
// Google Drive Upload hat die JSON ueberschrieben — wir brauchen die Originale
const transcribeItems = $("Transcribe Calls").all();
const driveItems = $input.all();

const transcripts = [];
for (let i = 0; i < transcribeItems.length; i++) {
  const orig = transcribeItems[i].json;
  const drive = driveItems[i]?.json || {};

  // Nur Items mit tatsaechlichen Transcript-Daten verarbeiten
  if (!orig.source_type || !orig.content) {
    continue;
  }

  const t = {
    source_type: orig.source_type,
    source_id: orig.source_id,
    lead_id: orig.lead_id,
    content: orig.content,
    call_type: orig.call_type,
    synced_at: orig.synced_at
  };

  // Google Drive Daten hinzufuegen (nur bei erfolgreichem Upload)
  if (drive.id && drive.mimeType) {
    t.google_drive_file_id = drive.id;
    t.google_drive_url = drive.webViewLink || "";
  }
  transcripts.push(t);
}

const skippedCalls = transcribeItems[0]?.json.skippedCalls || [];
return [{ json: { transcripts, skippedCalls, count: transcripts.length } }];

// Supabase Dedup + Call-Liste aufbereiten
const meta = $('Prepare Data').first().json;
const calls = $('Check Recordings').first().json.calls || [];
const skippedCalls = [];

let existingCallUuids = new Map();
let transcribedSourceIds = new Set();
let leadUuid = null;
let ownerUuid = null;

try {
  const leadResp = await this.helpers.httpRequest({
    method: 'GET',
    url: $env.SUPABASE_LEADS_URL + '/rest/v1/leads?select=id&close_lead_id=eq.' + meta.leadId + '&limit=1',
    headers: { 'apikey': $env.SUPABASE_LEADS_KEY, 'Authorization': 'Bearer ' + $env.SUPABASE_LEADS_KEY }
  });
  leadUuid = (Array.isArray(leadResp) && leadResp.length > 0) ? leadResp[0].id : null;

  if (leadUuid) {
    const sbCalls = await this.helpers.httpRequest({
      method: 'GET',
      url: $env.SUPABASE_LEADS_URL + '/rest/v1/calls?select=id,close_call_id&lead_id=eq.' + leadUuid,
      headers: { 'apikey': $env.SUPABASE_LEADS_KEY, 'Authorization': 'Bearer ' + $env.SUPABASE_LEADS_KEY }
    });
    for (const c of (Array.isArray(sbCalls) ? sbCalls : [])) {
      existingCallUuids.set(c.close_call_id, c.id);
    }

    if (existingCallUuids.size > 0) {
      const uuids = [...existingCallUuids.values()];
      const transcripts = await this.helpers.httpRequest({
        method: 'GET',
        url: $env.SUPABASE_LEADS_URL + '/rest/v1/transcripts?select=source_id&source_type=eq.call&source_id=in.(' + uuids.join(',') + ')',
        headers: { 'apikey': $env.SUPABASE_LEADS_KEY, 'Authorization': 'Bearer ' + $env.SUPABASE_LEADS_KEY }
      });
      for (const t of (Array.isArray(transcripts) ? transcripts : [])) {
        transcribedSourceIds.add(t.source_id);
      }
    }
  }
} catch (e) { /* Weiter ohne Dedup */ }

try {
  const userLookup = await this.helpers.httpRequest({
    method: 'GET',
    url: $env.SUPABASE_LEADS_URL + '/rest/v1/users?select=id&close_user_id=eq.' + meta.userId + '&limit=1',
    headers: { 'apikey': $env.SUPABASE_LEADS_KEY, 'Authorization': 'Bearer ' + $env.SUPABASE_LEADS_KEY }
  });
  if (Array.isArray(userLookup) && userLookup.length > 0) ownerUuid = userLookup[0].id;
} catch (e) {}

// Calls filtern
const callsToProcess = [];
for (const call of calls) {
  const callUuid = existingCallUuids.get(call.id);
  if (!callUuid) { skippedCalls.push({ id: call.id, reason: 'call_not_in_supabase' }); continue; }
  if (transcribedSourceIds.has(callUuid)) { skippedCalls.push({ id: call.id, reason: 'already_transcribed' }); continue; }
  callsToProcess.push({
    closeCallId: call.id,
    callUuid,
    recordingUrl: call.recording_url,
    duration: call.duration || 0,
  });
}

if (callsToProcess.length === 0) {
  return [{ json: { _noCallsToProcess: true, transcripts: [], skippedCalls, count: 0 } }];
}

// Ein Item pro Call
return callsToProcess.map(c => ({
  json: { ...c, leadUuid, ownerUuid, skippedCalls, totalCalls: callsToProcess.length }
}));

// Download + Whisper fuer EINEN Call (Memory-schonend)
const item = $json;
const MAX_SIZE = 25 * 1024 * 1024;
const CLOSE_AUTH = 'Basic YXBpXzJKd0JqaHMwYmZCUmJ5d3dHeXA0blUuMWlWV0NZVUUyRzE3NWh6NjJmNEJMRzo=';

try {
  // 1. Recording-URL aufloesen (302 → S3)
  let downloadUrl = item.recordingUrl;
  let needsAuth = true;

  try {
    const headResp = await this.helpers.httpRequest({
      method: 'HEAD',
      url: item.recordingUrl,
      headers: { 'Authorization': CLOSE_AUTH },
      disableFollowRedirect: true,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true
    });
    const loc = (headResp.headers || {}).location || (headResp.headers || {}).Location;
    if (loc) { downloadUrl = loc; needsAuth = false; }
  } catch (headErr) {
    const errHeaders = headErr?.response?.headers || headErr?.cause?.response?.headers || {};
    const loc = errHeaders.location || errHeaders.Location;
    if (loc) { downloadUrl = loc; needsAuth = false; }
  }

  // 2. Audio herunterladen
  const dlOpts = { method: 'GET', url: downloadUrl, encoding: 'arraybuffer' };
  if (needsAuth) dlOpts.headers = { 'Authorization': CLOSE_AUTH };
  let audioBuffer = await this.helpers.httpRequest(dlOpts);

  const bufSize = audioBuffer.byteLength || audioBuffer.length || 0;
  if (bufSize === 0) return [{ json: { ...item, _skipped: true, _reason: 'empty_recording' } }];
  if (bufSize > MAX_SIZE) return [{ json: { ...item, _skipped: true, _reason: 'too_large', _sizeMB: Math.round(bufSize/1024/1024) } }];

  // 3. Whisper Transkription
  const boundary = '----n8nBoundary' + Date.now();
  const modelPart = '--' + boundary + '\r\nContent-Disposition: form-data; name="model"\r\n\r\nwhisper-1\r\n';
  const langPart = '--' + boundary + '\r\nContent-Disposition: form-data; name="language"\r\n\r\nde\r\n';
  const fileHeader = '--' + boundary + '\r\nContent-Disposition: form-data; name="file"; filename="recording.mp3"\r\nContent-Type: audio/mpeg\r\n\r\n';
  const footer = '\r\n--' + boundary + '--\r\n';
  const bodyBuffer = Buffer.concat([Buffer.from(modelPart), Buffer.from(langPart), Buffer.from(fileHeader), Buffer.from(audioBuffer), Buffer.from(footer)]);

  const whisperResult = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.openai.com/v1/audio/transcriptions',
    headers: { 'Authorization': 'Bearer ' + $env.OPENAI_API_KEY, 'Content-Type': 'multipart/form-data; boundary=' + boundary },
    body: bodyBuffer
  });
  const transcriptText = typeof whisperResult === 'string' ? whisperResult : (whisperResult.text || JSON.stringify(whisperResult));

  // 4. Binary vorbereiten fuer Google Drive
  const fileName = 'call_' + item.closeCallId.substring(5, 20) + '_' + new Date().toISOString().substring(0, 10) + '.mp3';
  const binaryData = await this.helpers.prepareBinaryData(audioBuffer, fileName, 'audio/mpeg');

  // Buffer sofort freigeben
  audioBuffer = null;

  return [{
    json: {
      source_type: 'call',
      source_id: item.callUuid,
      lead_id: item.leadUuid,
      content: transcriptText,
      call_type: 'erstgespraech',
      synced_at: new Date().toISOString(),
      _fileName: fileName,
      _skipped: false,
      count: 1
    },
    binary: { data: binaryData }
  }];
} catch (e) {
  return [{ json: { ...item, _skipped: true, _reason: 'error', _message: e.message } }];
}

// Ergebnisse nach dem Loop sammeln
const items = $input.all();
const transcripts = [];
const skippedCalls = [];
let totalSkipped = [];

for (const item of items) {
  const j = item.json;
  if (j._skipped) {
    skippedCalls.push({ id: j.closeCallId, reason: j._reason, message: j._message || '' });
    continue;
  }
  if (j.source_type === 'call') {
    transcripts.push(j);
  }
  if (j.skippedCalls) totalSkipped = j.skippedCalls;
}

if (transcripts.length === 0) {
  return [{ json: { transcripts: [], skippedCalls: [...totalSkipped, ...skippedCalls], count: 0 } }];
}

// Items mit Binary-Daten durchreichen fuer Google Drive
const output = [];
for (const item of items) {
  if (!item.json._skipped && item.json.source_type === 'call') {
    output.push({
      json: { ...item.json, skippedCalls: [...totalSkipped, ...skippedCalls], count: transcripts.length },
      binary: item.binary || {}
    });
  }
}
return output;
